	// Get ASN to get its ID
	asnModel, err := r.postgresClient.GetASNByNumber(ctx, asn)
	if err != nil {
		return nil, fmt.Errorf("failed to get ASN: %w", err)
	}
	if asnModel == nil {
		return &model.ValidationResponse{
			ASN:    asn,
			Prefix: prefix,
			State:  model.NotFound,
			Reason: "ASN not found",
		}, nil
	}

	// Get prefix to get its ID
	prefixModel, err := r.postgresClient.GetPrefixByCIDR(ctx, prefix)
	if err != nil {
		return nil, fmt.Errorf("failed to get prefix: %w", err)
	}
	if prefixModel == nil {
		return &model.ValidationResponse{
			ASN:    asn,
			Prefix: prefix,
			State:  model.NotFound,
			Reason: "Prefix not found in database",
		}, nil
	}

	// Get all VRPs for this ASN
	vrps, err := r.postgresClient.GetVRPsByASN(ctx, asnModel.ID)
	if err != nil {
		return nil, fmt.Errorf("failed to get VRPs for ASN: %w", err)
	}

	result := r.prefixValidator.ValidatePrefix(asn, prefix, vrps)

	response := &model.ValidationResponse{
		ASN:    asn,
		Prefix: prefix,
		State:  result.State,
		Reason: result.Reason,
	}

	// Update the prefix validation state in DB
	if prefixModel != nil {
		err = r.postgresClient.UpdatePrefixValidationState(ctx, prefixModel.ID, result.State)
		if err != nil {
			// Log error but don't fail the response
			fmt.Printf("Failed to update prefix validation state: %v\n", err)
		}
	}

