func parseCursorToOffset(cursor string) (int, error) {
	id, err := decodeCursor(cursor)
	if err != nil {
		return 0, err
	}
	// This is a simple implementation - you might want to store actual offsets
	offset, err := strconv.Atoi(id)
	if err != nil {
		return 0, nil
	}
	return offset, nil
}
